import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { ApiService, errorMessage } from '../core/api.service';
import { Account } from '../core/models';

@Component({
  selector: 'app-accounts',
  standalone: true,
  imports: [FormsModule, RouterLink],
  templateUrl: './accounts.component.html',
  styleUrl: '../shared/list.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AccountsComponent implements OnInit {
  private readonly api = inject(ApiService);

  loading = signal(true);
  error = signal<string | null>(null);

  accounts = signal<Account[]>([]);

  name = signal('');
  industry = signal('');
  saving = signal(false);

  async ngOnInit(): Promise<void> {
    await this.load();
  }

  private async load(): Promise<void> {
    this.loading.set(true);
    try {
      this.accounts.set(await this.api.listAccounts());
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load accounts.'));
    } finally {
      this.loading.set(false);
    }
  }

  async create(): Promise<void> {
    this.error.set(null);
    if (!this.name().trim()) {
      this.error.set('Account name is required.');
      return;
    }
    this.saving.set(true);
    try {
      const account = await this.api.createAccount({
        name: this.name().trim(),
        industry: this.industry().trim() || undefined,
      });
      this.accounts.update((list) => [account, ...list]);
      this.name.set('');
      this.industry.set('');
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not create the account.'));
    } finally {
      this.saving.set(false);
    }
  }
}
